import{c as e,Q as a,j as n,m as r}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Anthropic \\"Dreaming\\": Offline Agent Self-Improvement — @Anthropic","description":"","frontmatter":{"title":"Anthropic \\"Dreaming\\": Offline Agent Self-Improvement — @Anthropic","author":"Anthropic（via VentureBeat coverage）","date":"2026-05-07T00:00:00.000Z","source":"https://venturebeat.com/technology/anthropic-introduces-dreaming-a-system-that-lets-ai-agents-learn-from-their-own-mistakes/","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-07-@anthropic-dreaming-offline-learning.md","filePath":"research/tweets/2026-05-07-@anthropic-dreaming-offline-learning.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-05-07-@anthropic-dreaming-offline-learning.md"};function o(i,t,l,c,d,p){return a(),n("div",null,[...t[0]||(t[0]=[r(`<h1 id="anthropic-dreaming-offline-agent-self-improvement-—-anthropic" tabindex="-1">Anthropic &quot;Dreaming&quot;: Offline Agent Self-Improvement — @Anthropic <a class="header-anchor" href="#anthropic-dreaming-offline-agent-self-improvement-—-anthropic" aria-label="Permalink to &quot;Anthropic &quot;Dreaming&quot;: Offline Agent Self-Improvement — @Anthropic&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://venturebeat.com/technology/anthropic-introduces-dreaming-a-system-that-lets-ai-agents-learn-from-their-own-mistakes/" target="_blank" rel="noreferrer">https://venturebeat.com/technology/anthropic-introduces-dreaming-a-system-that-lets-ai-agents-learn-from-their-own-mistakes/</a><strong>作者</strong>：Anthropic（via VentureBeat coverage） <strong>發布日期</strong>：2026-05-07（近似） <strong>收錄日期</strong>：2026-05-10 <strong>類型</strong>：Anthropic 官方功能公告 + 媒體報導 <strong>分類</strong>：harness-design / context-engineering</p><hr><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><blockquote><p>&quot;Dreaming allows AI agents to learn from mistakes offline — separate from the main task flow. Rather than blocking on mistakes during execution, agents accumulate error patterns and improve asynchronously.&quot;</p></blockquote><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Anthropic 引入「dreaming」機制——讓 agent 在離線（不阻斷主任務）狀態下從錯誤中學習。解耦了「執行時的學習」和「任務流的進行」，避免 context 污染。</p><h3 id="dreaming-的工作流程" tabindex="-1">Dreaming 的工作流程 <a class="header-anchor" href="#dreaming-的工作流程" aria-label="Permalink to &quot;Dreaming 的工作流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Main Task Flow (不被阻斷)</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ├── Error occurs → Error event 被記錄到 Dreaming buffer</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      └── Task continues...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Offline Dreaming Process (非同步)</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ├── 分析 buffer 中的 error patterns</span></span>
<span class="line"><span>      ├── 生成 improved heuristics / rules</span></span>
<span class="line"><span>      └── 更新 agent 的工作記憶（不影響進行中的 session）</span></span></code></pre></div><h3 id="harness-架構意涵" tabindex="-1">Harness 架構意涵 <a class="header-anchor" href="#harness-架構意涵" aria-label="Permalink to &quot;Harness 架構意涵&quot;">​</a></h3><table tabindex="0"><thead><tr><th>傳統方式</th><th>Dreaming 方式</th></tr></thead><tbody><tr><td>學習 = 同步，阻斷任務</td><td>學習 = 非同步，不阻斷</td></tr><tr><td>錯誤修正 = 中斷工作流</td><td>錯誤修正 = 下次 session 改善</td></tr><tr><td>Auto Memory = 扁平累積</td><td>Dreaming = 結構化反思</td></tr><tr><td>Context rot risk 高</td><td>Context 保持乾淨</td></tr></tbody></table><hr><h2 id="對-anthropic-alignment-md-的影響" tabindex="-1">對 ANTHROPIC-ALIGNMENT.md 的影響 <a class="header-anchor" href="#對-anthropic-alignment-md-的影響" aria-label="Permalink to &quot;對 ANTHROPIC-ALIGNMENT.md 的影響&quot;">​</a></h2><p>此功能直接對應 §六 延伸議題 <strong>議題 2：Post-task Reflection 機制</strong>：</p><blockquote><p>&quot;Memory Survey（2603.07670）實驗：移除反思 → 48 小時內行為退化。本 workspace 目前 Auto Memory 是扁平累積，沒有明確的「任務後反思」步驟。&quot;</p></blockquote><p>Dreaming 是 Anthropic 對此問題的官方解法。</p><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>相關性</td><td>9/10</td><td>直接對應 ANTHROPIC-ALIGNMENT.md 的開放議題</td></tr><tr><td>可行動性</td><td>7/10</td><td>Dreaming API 是否開放給 cc-workspace 使用？待確認</td></tr><tr><td>新穎性</td><td>9/10</td><td>非同步離線學習是新 harness 範式</td></tr><tr><td><strong>總評</strong></td><td><strong>8.3/10</strong></td><td>—</td></tr></tbody></table><hr><h2 id="與-cc-workspace-的連結" tabindex="-1">與 cc-workspace 的連結 <a class="header-anchor" href="#與-cc-workspace-的連結" aria-label="Permalink to &quot;與 cc-workspace 的連結&quot;">​</a></h2><ul><li><code>ANTHROPIC-ALIGNMENT.md</code> §六 議題 2 的進展追蹤</li><li>若 Dreaming 開放 API，考慮在 <code>session-stop.sh</code> 中觸發 dreaming reflection</li><li>關聯：<code>research/agent-harness/agent-memory-architecture-2026.md</code></li></ul>`,23)])])}const g=e(s,[["render",o]]);export{m as __pageData,g as default};
